import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth.ts';
import { candidatesAPI } from '../services/api.ts';

interface DashboardStats {
  total: number;
  pending: number;
  reviewing: number;
  approved: number;
  rejected: number;
}

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const [stats, setStats] = useState<DashboardStats>({
    total: 0,
    pending: 0,
    reviewing: 0,
    approved: 0,
    rejected: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      const response = await candidatesAPI.getAll();
      const candidates = response.candidates || [];

      const newStats = candidates.reduce((acc: DashboardStats, candidate) => {
        acc.total++;
        acc[candidate.status as keyof Omit<DashboardStats, 'total'>]++;
        return acc;
      }, {
        total: 0,
        pending: 0,
        reviewing: 0,
        approved: 0,
        rejected: 0
      });

      setStats(newStats);
    } catch (error) {
      console.error('Error loading dashboard stats:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <h1 className="text-xl font-semibold">Sistema de Concurso</h1>
            </div>
            <div className="flex items-center space-x-4">
              <span className="text-gray-700">Bem-vindo, {user?.name}</span>
              <button
                onClick={handleLogout}
                className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-md"
              >
                Sair
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <div className="px-4 py-6 sm:px-0">
          <div className="border-4 border-dashed border-gray-200 rounded-lg p-8">
            <h2 className="text-2xl font-bold mb-6">Dashboard</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              <div className="bg-white p-6 rounded-lg shadow">
                <h3 className="text-lg font-medium text-gray-900">Total de Candidatos</h3>
                <p className="text-3xl font-bold text-blue-600 mt-2">156</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow">
                <h3 className="text-lg font-medium text-gray-900">Pendentes</h3>
                <p className="text-3xl font-bold text-yellow-600 mt-2">23</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow">
                <h3 className="text-lg font-medium text-gray-900">Em Análise</h3>
                <p className="text-3xl font-bold text-purple-600 mt-2">45</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow">
                <h3 className="text-lg font-medium text-gray-900">Aprovados</h3>
                <p className="text-3xl font-bold text-green-600 mt-2">88</p>
              </div>
            </div>

            <div className="flex space-x-4">
              <button
                onClick={() => navigate('/candidates')}
                className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg font-medium"
              >
                Ver Candidatos
              </button>
              <button
                onClick={() => navigate('/candidates/new')}
                className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-medium"
              >
                Novo Candidato
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
